+import { NonExhaustiveError } from './errors';
+import { matchPattern } from './internals/helpers';
+import * as symbols from './internals/symbols';
+import type { Pattern } from './types/Pattern';
+import type { MatchEach } from './types/MatchEach';
+
+type Clause = { patterns: Pattern<any>[]; predicate?: (value: any) => unknown; handler: (selection: unknown, value: any) => unknown };
+type Step = Clause | { tap: (result: unknown) => void };
+
+/**
+ * Creates a pattern matching expression that runs every matching handler.
+ * It can be called with a value, or without one to build a reusable matcher.
+ */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, input, output>;
+export function matchEach(value?: unknown): MatchEach<any, any, any> {
+  return new MatchEachExpression([], arguments.length > 0, value) as any;
+}
+
+class MatchEachExpression {
+  constructor(private readonly steps: Step[], private readonly hasValue: boolean, private readonly value: unknown) {}
+
+  with(...args: any[]): MatchEachExpression {
+    const handler = args[args.length - 1];
+    let patterns: Pattern<any>[] = [args[0]];
+    let predicate: ((value: any) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns = args.slice(0, -1);
+    return this.next({ patterns, predicate, handler });
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown): MatchEachExpression {
+    return this.next({ patterns: [], predicate, handler: (_selection, value) => handler(value) });
+  }
+
+  tap(callback: (result: unknown) => void): MatchEachExpression {
+    return this.next({ tap: callback });
+  }
+
+  otherwise(handler: (value: unknown) => unknown): unknown[] {
+    const results = this.evaluate(this.value);
+    return results === undefined ? [handler(this.value)] : results;
+  }
+
+  exhaustive(fallback?: (value: unknown) => unknown): unknown[] {
+    const results = this.evaluate(this.value);
+    if (results !== undefined) return results;
+    if (fallback) return [fallback(this.value)];
+    throw new NonExhaustiveError(this.value);
+  }
+
+  run(): unknown[] { return this.exhaustive(); }
+  returnType(): this { return this; }
+  narrow(): this { return this; }
+
+  toFunction(): (input: unknown) => unknown[] {
+    return (input) => {
+      const results = this.evaluate(input);
+      if (results === undefined) throw new NonExhaustiveError(input);
+      return results;
+    };
+  }
+
+  toExhaustiveFunction(): (input: unknown) => unknown[] { return this.toFunction(); }
+
+  toPartialFunction(): (input: unknown) => unknown[] | undefined {
+    return (input) => this.evaluate(input);
+  }
+
+  private next(step: Step): MatchEachExpression {
+    return new MatchEachExpression([...this.steps, step], this.hasValue, this.value);
+  }
+
+  private evaluate(input: unknown): unknown[] | undefined {
+    const results: unknown[] = [];
+    let matched = false;
+    for (const step of this.steps) {
+      if ('tap' in step) {
+        for (const result of results) step.tap(result);
+        continue;
+      }
+      let hasSelections = false;
+      const selected: Record<string, unknown> = {};
+      const select = (key: string, value: unknown) => { hasSelections = true; selected[key] = value; };
+      const clauseMatched = step.patterns.length === 0
+        ? Boolean(step.predicate!(input))
+        : step.patterns.some((pattern) => matchPattern(pattern, input, select)) && (!step.predicate || Boolean(step.predicate(input)));
+      if (!clauseMatched) continue;
+      matched = true;
+      const selections = hasSelections
+        ? symbols.anonymousSelectKey in selected ? selected[symbols.anonymousSelectKey] : selected
+        : input;
+      results.push(step.handler(selections, input));
+    }
